fn test_handler_spawned_tasks_cleaned_up() {
    let lab = LabRuntime::new();
    let spawned_count = AtomicUsize::new(0);

    lab.block_on(async {
        let cx = lab.cx();

        // Handler that spawns background tasks
        let result = cx.region(|rcx| async {
            for _ in 0..10 {
                rcx.spawn(async {
                    spawned_count.fetch_add(1, Ordering::SeqCst);
                    sleep(Duration::from_secs(3600)).await;  // Would run "forever"
                });
            }
            Outcome::Ok(Response::ok())
        }).await;

        assert!(result.is_ok());

        // Verify: all 10 tasks were spawned
        assert_eq!(spawned_count.load(Ordering::SeqCst), 10);
    });

    // Verify: TaskLeakOracle passes (no leaked tasks)
    lab.assert_no_task_leaks();
}
