        region_id: RegionId,
        outcome_kind: OutcomeKind,
        children_count: usize,
        finalizers_run: usize,
    },

    // === Cancellation ===
    CancelRequest {
        target: CancelTarget,  // Region or Task
        reason: CancelReason,
        budget: Budget,
    },
    CancelPropagate {
        from: RegionId,
