## TraceBuffer

```rust
/// Ring buffer for trace events with configurable capacity
pub struct TraceBuffer {
    events: Vec<(Time, TraceEvent)>,
    capacity: usize,
    write_pos: usize,
    overflow_count: u64,
}

impl TraceBuffer {
    pub fn new(capacity: usize) -> Self;

    /// Record an event with timestamp
    pub fn push(&mut self, time: Time, event: TraceEvent);

    /// Get all events (in order)
    pub fn events(&self) -> impl Iterator<Item = &(Time, TraceEvent)>;

    /// Get events since a timestamp
    pub fn events_since(&self, since: Time) -> impl Iterator<Item = &(Time, TraceEvent)>;

    /// Get events matching a filter
    pub fn filter<F>(&self, f: F) -> Vec<&(Time, TraceEvent)>
    where
        F: Fn(&TraceEvent) -> bool;

    /// Clear all events
    pub fn clear(&mut self);

    /// Export for analysis (JSON-serializable)
    pub fn export(&self) -> TraceExport;

    /// Check if buffer has overflowed
    pub fn has_overflow(&self) -> bool;

    /// Get overflow count
    pub fn overflow_count(&self) -> u64;
}
```

